import{_ as t,o,c as a,a3 as n}from"./chunks/framework.CjquFG0V.js";const g=JSON.parse('{"title":"26. Ending Employment During Parental Leave","description":"","frontmatter":{"title":"26. Ending Employment During Parental Leave","eba":"Allied Health Professionals 2021-2026","topics":["leave","parental-leave","consultation"]},"headers":[],"relativePath":"ebas/allied-health/employment/26-ending-employment-during-parental-leave.md","filePath":"ebas/allied-health/employment/26-ending-employment-during-parental-leave.md"}'),i={name:"ebas/allied-health/employment/26-ending-employment-during-parental-leave.md"};function l(r,e,s,p,h,d){return o(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="_26-ending-employment-during-parental-leave" tabindex="-1">26. Ending Employment During Parental Leave <a class="header-anchor" href="#_26-ending-employment-during-parental-leave" aria-label="Permalink to &quot;26. Ending Employment During Parental Leave&quot;">​</a></h1><p><strong>26.1</strong> Communication during parental leave – organisational change</p><p><strong>(a)</strong> Organisational Change - consultation Where an Eligible Employee (as defined in subclause 70.2) is on parental leave and the Employer proposes a change that will have a Significant Effect within the meaning of <a href="/eba/ebas/allied-health/consultation-disputes/13-consultation.html">clause 13</a> (Consultation) of this Agreement on the Eligible Employee, including their pre-parental leave position, the Employer will comply with the requirements of <a href="/eba/ebas/allied-health/consultation-disputes/13-consultation.html">clause 13</a> (Consultation) which include but are not limited to providing:</p><p><strong>(i)</strong> information in accordance with subclause 13.4; and</p><p><strong>(ii)</strong> an opportunity for discussions with the Eligible Employee and, where relevant, the Eligible Employee’s representative in accordance with subclause 13.6. Where the organisational change may result in the Eligible Employee’s position being made redundant, the provisions in subclause 26.2 will also apply.</p><p><strong>(b)</strong> Other significant matters The Eligible Employee will endeavour to take reasonable steps as soon as practicable to inform the Employer about any significant matter that arises whilst the Eligible Employee is on parental leave that will affect the Eligible Employee’s decision regarding:</p><p><strong>(i)</strong> the duration of parental leave to be taken;</p><p><strong>(ii)</strong> whether the Eligible Employee intends to return to work; and</p><p><strong>(iii)</strong> whether the Eligible Employee intends to request to return to work on a</p><p><strong>(c)</strong> Change of address The Eligible Employee will also notify the Employer of changes of address or other contact details which might affect the Employer’s capacity to comply with subclause 26.1.</p><p><strong>26.2</strong> Redundancy – proposed termination of Employment</p><p><strong>(a)</strong> Employer to write to Employee Where, following the consultation in <a href="/eba/ebas/allied-health/consultation-disputes/13-consultation.html">clause 13</a>, an Eligible Employee is on parental leave when the Eligible Employee’s role is declared redundant, the Employer will inform the Eligible Employee in writing of the following:</p><p><strong>(i)</strong> that the Eligible Employee is entitled to return to an available position for which the Eligible Employee is qualified and suited nearest in status and pay to the pre-parental leave position;</p><p><strong>(ii)</strong> any available position/s for which the Employer believes the Eligible Employee may be qualified and suited, including those nearest in status and pay to the pre-parental leave position; and</p><p><strong>(iii)</strong> In the event that: A. the available position for which the Employee is qualified and suited nearest in status and pay to the pre-parental leave position is not a Comparable Role within the meaning of subclause 25.2(b); or B. there is no available position as described at subclause 26.2(a)(iii)A; the Eligible Employee may: (1) continue the employment by electing to defer the commencement of the redeployment period in subclause 25.3 for the period of parental leave, including any extension agreed under subclause 70.14 (although nothing in this clause 26 stops a Comparable Role from being identified during parental leave, before the redeployment period); or (2) consent to the termination of employment when the position is made redundant and receive the redundancy entitlements in accordance with subclause 25.8;</p><p><strong>(iv)</strong> in the event that the Eligible Employee is informed by the Employer of a Comparable Role, the consequences under subclause 25.3(d)(Rejecting a Comparable Role) of not accepting a Comparable Role; and</p><p><strong>(v)</strong> that the Eligible Employee is entitled to a representative which may be a Union representative.</p><p><strong>(b)</strong> Eligible Employee to advise Employer in writing</p><p><strong>(i)</strong> The Eligible Employee will advise the Employer in writing whether:</p><p>A. the Eligible Employee consents to the proposed termination of employment during the period of parental leave due to redundancy; B. where applicable, the Eligible Employee accepts redeployment into the available position for which the Eligible Employee is qualified and suited nearest in status and pay to the pre-parental leave position; or C. the Eligible Employee elects to defer the commencement of the redeployment period in subclause 25.3 (Redeployment) for the duration of parental leave;</p><p><strong>(ii)</strong> within fourteen days of receiving the Employer’s written advice outlined at subclause 26.2(a) or if that is not practicable, as soon as practicable.</p><p><strong>(iii)</strong> The Employee will not be in breach of subclause 26.2(b)(i) if a failure to respond is reasonable in the circumstances.</p><p><strong>(iv)</strong> At any time during the parental leave the Eligible Employee may advise the Employer in writing that they consent to the proposed termination of employment during the period of parental leave due to redundancy.</p><p><strong>(c)</strong> Eligible Employee elects to remain employed Where the Eligible Employee does not consent to the proposed termination of employment during the period of parental leave due to redundancy, the parties (or representatives, which may be the Union) will discuss and agree how the Employer will communicate with the Employee during parental leave to maximise the likelihood of the Employee being offered a Comparable Role.</p><p><strong>(d)</strong> Comparable Role does not affect length of parental leave Where a Comparable Role or other position is accepted by the Employee the Employer will redeploy them to that role or position. In such a circumstance, the Employer will not require the Eligible Employee to vary the length of the parental leave and the Employee’s right to request an extension to parental leave under subclause 70.14 is not affected.</p><p>Example: An Eligible Employee’s role is made redundant six (6) months through a 12- month period of parental leave. The Eligible Employee elects to defer the commencement of the redeployment period. A Comparable Role is accepted by the Eligible Employee. The Eligible Employee is entitled to return to the Comparable Role at the end of the 12-month parental leave period or a longer or shorter period as agreed. The Employer may fill the Comparable role on a temporary basis (such as fixed term) until the end of the Eligible Employee’s parental leave.</p><p><strong>(e)</strong> No Comparable Role by the end of parental leave</p><p><strong>(i)</strong> Where the Eligible Employee has not accepted a Comparable Role or other position before the conclusion of parental leave: A. the Employer will advise the Eligible Employee in writing of any</p><p>available positions for which the Employee is qualified and suited, including those nearest in status and pay to the pre- parental leave position even if it is not a Comparable Role; and B. the Employer will state whether, in its view, the available position is a Comparable Role.</p><p><strong>(ii)</strong> Where the Eligible Employee does not wish to exercise the right to return to the available position, the Eligible Employee may elect to commence the redeployment period in subclause 25.3 or terminate the employment on the basis of redundancy.</p><p><strong>(f)</strong> Calculation of payments</p><p><strong>(i)</strong> Where an Eligible Employee’s employment is terminated, in accordance with this clause 26, prior to returning to work from parental leave, any severance pay (including notice) and any other amount owing to the Employee will be based on the higher of: A. the position the Eligible Employee held immediately before proceeding on parental leave; or B. in the case of an Eligible Employee who transferred to a safe job pursuant to subclause 70.16, the position they held immediately before such transfer; calculated at the hourly rate at the time the termination takes effect. Example: An Eligible Employee works 30 hours a week (Job A) prior to transferring to a safe job which is at a lower pay rate and is for only 25 hours a week (Job B). A wage increase occurs during the parental leave. Redundancy is calculated on the basis of Job A’s rate of pay as increased during the period of parental leave and its greater number of hours per week.</p><p><strong>(ii)</strong> In the event that the Eligible Employee consents to the termination of employment due to redundancy during paid parental leave, the Eligible Employee will receive the full amount of paid parental leave and superannuation under subclauses 70.7 and 30.5.</p><p><strong>(g)</strong> Resignation does not affect redundancy payment Resignation by the Eligible Employee prior to returning to work does not affect the Employee’s entitlement to a redundancy payment under subclause 25.8.</p><p><strong>(h)</strong> Redeployment period Where an Eligible Employee’s role is made redundant during parental leave, and:</p><p><strong>(i)</strong> the Employee has not consented to the proposed termination of their employment during the period of parental leave due to redundancy; and/or</p><p><strong>(ii)</strong> the Eligible Employee has not accepted a Comparable Role or an available position for which the Eligible Employee is qualified and suited nearest in status and pay to the pre-parental leave position; the redeployment period of 13 weeks in subclause 25.3 commences on the day after the Employee’s parental leave ends.</p><p>Plain language terms: maternity, paternity, baby leave.</p>',38)])])}const c=t(i,[["render",l]]);export{g as __pageData,c as default};
